import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"[Đặc tả BA] Module: Quản trị Nội dung (Content Management)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/01-dac-ta-chi-tiet.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/01-dac-ta-chi-tiet.md"}'),e={name:"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/01-dac-ta-chi-tiet.md"};function h(l,n,r,u,s,c){return i(),a("div",null,[...n[0]||(n[0]=[o('<h1 id="đac-ta-ba-module-quan-tri-noi-dung-content-management" tabindex="-1">[Đặc tả BA] Module: Quản trị Nội dung (Content Management) <a class="header-anchor" href="#đac-ta-ba-module-quan-tri-noi-dung-content-management" aria-label="Permalink to &quot;[Đặc tả BA] Module: Quản trị Nội dung (Content Management)&quot;">​</a></h1><p>Module này chịu trách nhiệm quản lý toàn bộ &quot;Sản phẩm&quot; và &quot;Dữ liệu nguồn&quot; của Vivu Travel.</p><h2 id="_1-quan-ly-điem-đen-destinations" tabindex="-1">1. Quản lý Điểm đến (Destinations) <a class="header-anchor" href="#_1-quan-ly-điem-đen-destinations" aria-label="Permalink to &quot;1. Quản lý Điểm đến (Destinations)&quot;">​</a></h2><ul><li><strong>Nền tảng</strong>: Web Admin.</li><li><strong>Mục tiêu</strong>: Định danh các địa danh và vùng miền.</li><li><strong>Chi tiết trường dữ liệu</strong>: <ul><li><code>Region</code>: Miền Bắc, Miền Trung, Miền Nam.</li><li><code>Destination Name</code>: Tên địa danh (Hạ Long, Đà Lạt...).</li><li><code>Lat/Long</code>: Tọa độ thực để hiển thị bản đồ trên Mobile.</li><li><code>Gallery</code>: Bộ sưu tập ảnh (Hỗ trợ kéo thả upload).</li></ul></li><li><strong>Business Rule</strong>: Tên điểm đến + Vùng miền phải là duy nhất. Khi xóa điểm đến, hệ thống phải kiểm tra xem có Tour nào đang sử dụng không.</li></ul><h2 id="_2-quan-ly-tour-du-lich-tours" tabindex="-1">2. Quản lý Tour du lịch (Tours) <a class="header-anchor" href="#_2-quan-ly-tour-du-lich-tours" aria-label="Permalink to &quot;2. Quản lý Tour du lịch (Tours)&quot;">​</a></h2><ul><li><strong>Nền tảng</strong>: Web Admin.</li><li><strong>Mục tiêu</strong>: Tạo sản phẩm kinh doanh chính.</li><li><strong>Cấu trúc Tour</strong>: <ul><li><strong>Thông tin cơ bản</strong>: Tên tour, Giá gốc, Giá khuyến mãi.</li><li><strong>Lịch trình (Itinerary)</strong>: Nhập liệu theo Ngày (Ngày 1: ..., Ngày 2: ...).</li><li><strong>Phân loại (Tags)</strong>: Gia đình, Mạo hiểm, Nghỉ dưỡng.</li><li><strong>Chính sách</strong>: Quy định hoàn hủy, Bao gồm/Không bao gồm.</li></ul></li><li><strong>Business Rule</strong>: Tour phải thuộc về 1 Destination. Tour có thể có &quot;Ngày khởi hành&quot; linh hoạt (Fixed date hoặc Daily).</li></ul><h2 id="_3-khach-san-media" tabindex="-1">3. Khách sạn &amp; Media <a class="header-anchor" href="#_3-khach-san-media" aria-label="Permalink to &quot;3. Khách sạn &amp; Media&quot;">​</a></h2><ul><li>Quản lý Hạng sao, Tiện ích, Loại phòng.</li><li>Thư viện Media tập trung, tự động tối ưu WebP cho Mobile.</li></ul>',8)])])}const m=t(e,[["render",h]]);export{g as __pageData,m as default};
